import { useEffect, useRef } from 'react';

import { AnnotationsCustomizedTooltip } from './AnnotationsCustomizedTooltip.js';
import { AnnotationsDefaultTooltipContent } from './AnnotationsDefaultTooltipContent.js';
import { useAnnotationsTooltipConfig } from './hooks/useAnnotationsTooltipConfig.js';
import type { TruncationMode } from '../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { OverlayTooltip } from '../../../overlay-tooltip/OverlayTooltip.js';
import type { Data } from '../../../overlay-tooltip/types.js';
import { useTooltipReducer } from '../../../overlay-tooltip/useTooltipReducer.js';
import { emptyData } from '../../../overlay-tooltip/utils.js';
import { useAnnotationsTooltipState } from '../../hooks/store/selectors.js';
import {
  useSetStateSelection,
  useSetStateTooltip,
} from '../../hooks/store/state-setters.js';
import { useMarkersInteractions } from '../../hooks/useMarkersInteractions.js';
import { initialState } from '../../providers/AnnotationsDataInitialState.js';

interface AnnotationsOverlayTooltipProps {
  tooltipType: 'time' | 'numerical';
  truncationMode?: TruncationMode;
  maxLines?: number;
}

// Sentinel payload used to keep the OverlayTooltip store data non-empty while
// the annotations tooltip is visible. The actual content is rendered through
// `legacyTemplate`, so this value is never read by the default tooltip
// rendering pipeline — it only has to pass `isTooltipDataEmpty` (geometry !==
// 'none') so that DynamicTooltipRenderer mounts the portal.
const buildSentinelData = (): Data => ({
  geometry: 'rect',
  series: [
    {
      name: '',
      value: '',
      color: '',
    },
  ],
});

/**
 * AnnotationsChart tooltip driven by the shared OverlayTooltip
 * (`TooltipProvider`) store. Bridges the legacy annotations store into the
 * shared store so that positioning, pinning and out-of-bounds handling are
 * identical to XYChart and MeterBar tooltips.
 *
 * The actual UI is rendered via `<OverlayTooltip legacyTemplate={...}/>` so
 * we can keep AnnotationsChart's bespoke layout (multiple Header+Series pairs
 * for collided marker groups, custom user templates, etc.) while reusing the
 * shared portal / pin / dismissal behaviour.
 *
 * @internal
 */
export const AnnotationsOverlayTooltip = (
  props: AnnotationsOverlayTooltipProps,
) => {
  const { tooltipType, truncationMode = 'end', maxLines = 1 } = props;
  const annotationsState = useAnnotationsTooltipState();
  const { pinned, data, visibility, position } = annotationsState;
  const dispatch = useTooltipReducer();
  const updateAnnotationsTooltipState = useSetStateTooltip();
  const updateAnnotationsSelectionState = useSetStateSelection();
  const onMarkersInteraction = useMarkersInteractions();

  const config = useAnnotationsTooltipConfig();
  const hidden = config?.hidden === true;
  const hasData = !!data && data.length > 0 && visibility;

  // Track the previous pinned state so we can explicitly dispatch
  // SET_PINNED(false) on a true -> false transition (the reducer's
  // SET_POSITION/SET_OUT_BOUNDS branches short-circuit while pinned is true).
  const prevPinnedRef = useRef(false);

  // Sync annotations store into the OverlayTooltip store on changes so that
  // the shared tooltip portal reflects the current hover/pin state.
  useEffect(() => {
    const wasPinned = prevPinnedRef.current;
    prevPinnedRef.current = pinned;

    if (wasPinned && !pinned) {
      // Explicit unpin first — otherwise SET_POSITION / SET_OUT_BOUNDS below
      // will no-op because the reducer treats `pinned=true` as sticky.
      dispatch({
        type: 'SET_PINNED',
        payload: {
          pinned: false,
          data: emptyData(),
        },
      })();
    }

    if (hidden || !hasData || !position) {
      dispatch({ type: 'SET_OUT_BOUNDS' })();
      return;
    }

    if (pinned) {
      dispatch({
        type: 'SET_PINNED',
        payload: {
          pinned: true,
          absoluteX: position.x,
          absoluteY: position.y,
          data: buildSentinelData(),
        },
      })();
    } else {
      dispatch({
        type: 'SET_POSITION',
        payload: {
          absoluteX: position.x,
          absoluteY: position.y,
          data: buildSentinelData(),
        },
      })();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [hidden, hasData, pinned, position?.x, position?.y]);

  // Reset both the OverlayTooltip and annotations stores on unmount.
  useEffect(() => {
    return () => {
      dispatch({ type: 'RESET_TOOLTIP' })();
      updateAnnotationsTooltipState(initialState.tooltip);
      updateAnnotationsSelectionState(initialState.selection);
      onMarkersInteraction?.(initialState.selection);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key !== 'Escape') {
        return;
      }
      updateAnnotationsTooltipState(initialState.tooltip);
      updateAnnotationsSelectionState(initialState.selection);
      onMarkersInteraction?.(initialState.selection);
    };
    window.addEventListener('keyup', handleEscape);
    return () => {
      window.removeEventListener('keyup', handleEscape);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (hidden || !hasData) {
    return null;
  }

  const legacyTemplate = config?.template ? (
    <AnnotationsCustomizedTooltip
      tooltipTemplate={config.template}
      data={data}
    />
  ) : (
    <AnnotationsDefaultTooltipContent
      data={data}
      tooltipType={tooltipType}
      truncationMode={truncationMode}
      maxLines={maxLines}
    />
  );

  return <OverlayTooltip legacyTemplate={legacyTemplate} />;
};

AnnotationsOverlayTooltip.displayName = 'AnnotationsOverlayTooltip';
